const numbersToWords=I=>{const N=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(I<0x14)return N[I];if(I<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](I/0xa)]+(I%0xa?'\x20'+N[I%0xa]:'');if(I<0x3e8){const h=Math['floor'](I/0x64),A=I%0x64;return(0x1===h?'εκατό':0x2===h?'διακόσια':0x3===h?'τριακόσια':0x4===h?'τετρακόσια':0x5===h?'πεντακόσια':0x6===h?'εξακόσια':0x7===h?'επτακόσια':0x8===h?'οκτακόσια':0x9===h?'εννιακόσια':'')+(A?'\x20'+numbersToWords(A):'');}return I<0xf4240?numbersToWords(Math['floor'](I/0x3e8))+'\x20χιλιάδες'+(I%0x3e8?'\x20'+numbersToWords(I%0x3e8):''):numbersToWords(Math['floor'](I/0xf4240))+'\x20εκατομμύρια'+(I%0xf4240?'\x20'+numbersToWords(I%0xf4240):'');},numberToText=(I,N='money')=>{const h=Math['floor'](I),A=Math['round'](0x64*(I-h));let u=numbersToWords(h),Y=A>0x0?numbersToWords(A):'';switch(N){case'money':return Y?u+'\x20ευρώ\x20και\x20'+Y+'\x20λεπτά':u+'\x20ευρώ';case'time':return Y?u+'\x20ώρες\x20και\x20'+Y+'\x20λεπτά':u+'\x20ώρες';default:return Y?u+'\x20και\x20'+Y:''+u;}};